#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MAX_N 1000
#define MAX_K 1000

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int prices[N], discounts[K];
        for (int i = 0; i < N; i++) {
            scanf("%d", &prices[i]);
        }
        for (int i = 0; i < K; i++) {
            scanf("%d", &discounts[i]);
        }
        qsort(discounts, K, sizeof(int), compare);
        qsort(prices, N, sizeof(int), compare);
        double expected_discount = 0;
        // calculate expected discount
        int total_combinations = 1;
        for (int i = N; i > N - K; i--) {
            total_combinations *= i;
        }
        for (int i = 1; i <= K; i++) {
            total_combinations /= i;
        }
        for (int mask = 0; mask < (1 << N); mask++) {
            int count = 0;
            int current_prices[K];
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i)) != 0) {
                    current_prices[count++] = prices[i];
                }
            }
            if (count == K) {
                double current_discount = 0;
                for (int i = 0; i < K; i++) {
                    current_discount += (current_prices[i] * discounts[K - i - 1]) / 100.0;
                }
                expected_discount += current_discount;
            }
        }
        expected_discount /= total_combinations;
        printf("%.3f\n", expected_discount);
    }
    return 0;
}

