const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextLine() {
    return lines[idx++];
}

function nextInt() {
    return parseInt(nextLine());
}

function nextInts() {
    return nextLine().split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let [N, K] = nextInts();
    let prices = nextInts();
    let discounts = nextInts().sort((a, b) => b - a);
    let expected_discount = 0;
    let total_combinations = 0;
    let combos = getCombinations(prices, K);
    for (let combo of combos) {
        let current_discount = 0;
        let sorted_combo = combo.sort((a, b) => b - a);
        for (let i = 0; i < K; i++) {
            current_discount += (sorted_combo[i] * discounts[i]) / 100;
        }
        expected_discount += current_discount;
        total_combinations++;
    }
    expected_discount /= total_combinations;
    console.log(expected_discount.toFixed(3));
}

function getCombinations(arr, len) {
    if (len === 1) return arr.map(x => [x]);
    let result = [];
    for (let i = 0; i < arr.length; i++) {
        let current = arr[i];
        let rest = arr.slice(i + 1);
        for (let p of getCombinations(rest, len - 1)) {
            result.push([current, ...p]);
        }
    }
    return result;
}

